-- 010_breeds_working.sql
-- Adds is_working_breed flag based on FCI breed pages
-- "Subject to a working trial according to the FCI Breeds Nomenclature"

ALTER TABLE breeds ADD COLUMN is_working_breed BOOLEAN NOT NULL DEFAULT false;

UPDATE breeds SET is_working_breed = true WHERE fci_id IN (1, 2, 5, 6, 7, 10, 12, 15, 17, 19, 20, 21, 22, 24, 25, 28, 30, 31, 32, 33, 34, 35, 36, 42, 44, 48, 49, 51, 52, 57, 59, 60, 62, 63, 66, 67, 68, 70, 78, 84, 90, 95, 98, 99, 100, 102, 103, 104, 105, 106, 107, 108, 109, 110, 111, 113, 114, 115, 117, 118, 119, 120, 121, 122, 123, 124, 125, 126, 127, 129, 130, 131, 132, 133, 134, 138, 141, 143, 144, 147, 148, 150, 151, 152, 154, 155, 159, 161, 163, 165, 166, 169, 171, 175, 176, 177, 179, 180, 181, 187, 190, 191, 194, 198, 199, 202, 203, 204, 213, 214, 216, 217, 219, 220, 221, 222, 223, 224, 229, 232, 239, 241, 242, 244, 245, 254, 263, 266, 267, 268, 274, 276, 279, 281, 282, 290, 293, 295, 297, 298, 299, 301, 303, 304, 305, 306, 312, 316, 320, 322, 323, 324, 325, 330, 332, 336, 337, 339, 343, 345, 354, 361, 364, 365, 366, 371);
